	if peerIdx < 0 || peerIdx >= len(m.peers) {
		return nil, fmt.Errorf("bind: peer index %d out of range [0,%d)", peerIdx, len(m.peers))
	}
	return m.peers[peerIdx].reflector.Reflect(raw)
}

