	if err != nil {
		t.Fatalf("PeerBootProbe(edge-1): %v", err)
	}
	if !decodesAsProbe(t, psk1, probe1) {
		t.Fatal("edge-1's boot probe does NOT verify under its OWN psk — its prober is keyed on the wrong peer's psk (device.go:301)")
